    #[test]
    fn test_inspector_ffi_context_lifecycle_event_payloads() {
        let iso = IsolateGuard::new();
        let ctx = unsafe { stator_context_new(iso.as_ptr()) };
        let inspector = unsafe { stator_inspector_create(ctx) };
        let session = unsafe { stator_inspector_connect(inspector, 1) };

        let enable = br#"{"id":1,"method":"Runtime.enable","params":{}}"#;
        assert_eq!(
            unsafe {
                stator_inspector_dispatch(session, enable.as_ptr() as *const c_char, enable.len())
            },
            0
        );
        let _ = drain_inspector_session(session);

        let origin = b"https://edge.example";
        let name = b"isolated-world";
        let group_id = unsafe {
            stator_inspector_create_context_group(
                inspector,
                origin.as_ptr() as *const c_char,
                origin.len(),
                name.as_ptr() as *const c_char,
                name.len(),
            )
        };
        let context_id = unsafe {
            stator_inspector_create_context(
                inspector,
                group_id,
                origin.as_ptr() as *const c_char,
                origin.len(),
                name.as_ptr() as *const c_char,
                name.len(),
            )
        };
        assert_eq!(context_id, 2);
        assert_eq!(unsafe { stator_inspector_pending_count(session) }, 1);

        let created_msgs = drain_inspector_session(session);
        let created: serde_json::Value = serde_json::from_str(&created_msgs[0]).unwrap();
        assert_eq!(created["method"], "Runtime.executionContextCreated");
        assert_eq!(created["params"]["context"]["id"], context_id);
        assert_eq!(
            created["params"]["context"]["origin"],
            "https://edge.example"
        );
        assert_eq!(created["params"]["context"]["name"], "isolated-world");
        assert_eq!(created["params"]["context"]["uniqueId"], "stator-2-2");
        assert_eq!(created["params"]["context"]["auxData"]["groupId"], group_id);

        assert!(unsafe { stator_inspector_destroy_context(inspector, context_id) });
        assert!(!unsafe { stator_inspector_destroy_context(inspector, context_id) });
        let destroyed_msgs = drain_inspector_session(session);
        assert_eq!(destroyed_msgs.len(), 1);
        let destroyed: serde_json::Value = serde_json::from_str(&destroyed_msgs[0]).unwrap();
        assert_eq!(destroyed["method"], "Runtime.executionContextDestroyed");
        assert_eq!(destroyed["params"]["executionContextId"], context_id);

        unsafe {
            stator_inspector_disconnect(inspector, session);
            stator_inspector_destroy(inspector);
            stator_context_destroy(ctx);
        }
    }

    #[test]
    fn test_inspector_ffi_context_group_clear_isolated_and_idempotent() {
        let iso = IsolateGuard::new();
        let ctx = unsafe { stator_context_new(iso.as_ptr()) };
        let inspector = unsafe { stator_inspector_create(ctx) };
        let session = unsafe { stator_inspector_connect(inspector, 1) };

        let enable = br#"{"id":1,"method":"Runtime.enable","params":{}}"#;
        assert_eq!(
            unsafe {
                stator_inspector_dispatch(session, enable.as_ptr() as *const c_char, enable.len())
            },
            0
        );
        let _ = drain_inspector_session(session);

        let origin_a = b"a";
        let origin_b = b"b";
        let group_a = unsafe {
            stator_inspector_create_context_group(
                inspector,
                origin_a.as_ptr() as *const c_char,
                origin_a.len(),
                origin_a.as_ptr() as *const c_char,
                origin_a.len(),
            )
        };
        let group_b = unsafe {
            stator_inspector_create_context_group(
                inspector,
                origin_b.as_ptr() as *const c_char,
                origin_b.len(),
                origin_b.as_ptr() as *const c_char,
                origin_b.len(),
            )
        };
        assert_eq!(
            unsafe {
                stator_inspector_create_context(
                    inspector,
                    group_a,
                    origin_a.as_ptr() as *const c_char,
                    origin_a.len(),
                    origin_a.as_ptr() as *const c_char,
                    origin_a.len(),
                )
            },
            2
        );
        assert_eq!(
            unsafe {
                stator_inspector_create_context(
                    inspector,
                    group_a,
                    origin_a.as_ptr() as *const c_char,
                    origin_a.len(),
                    origin_a.as_ptr() as *const c_char,
                    origin_a.len(),
                )
            },
            3
        );
        assert_eq!(
            unsafe {
                stator_inspector_create_context(
                    inspector,
                    group_b,
                    origin_b.as_ptr() as *const c_char,
                    origin_b.len(),
                    origin_b.as_ptr() as *const c_char,
                    origin_b.len(),
                )
            },
            4
        );
        let _ = drain_inspector_session(session);

        assert_eq!(
            unsafe { stator_inspector_clear_context_group(inspector, group_a) },
            2
        );
        assert_eq!(
            unsafe { stator_inspector_clear_context_group(inspector, group_a) },
            0
        );
        assert_eq!(unsafe { stator_inspector_context_count(inspector) }, 2);

        let msgs = drain_inspector_session(session);
        assert_eq!(msgs.len(), 1);
        let cleared: serde_json::Value = serde_json::from_str(&msgs[0]).unwrap();
        assert_eq!(cleared["method"], "Runtime.executionContextsCleared");

        unsafe {
            stator_inspector_disconnect(inspector, session);
            stator_inspector_destroy(inspector);
            stator_context_destroy(ctx);
        }
    }

    // ── Persistent handles ────────────────────────────────────────────────────

    /// Test helper: create a context on `iso` and tear it down in `Drop`.
    struct ContextGuard {
        ctx: *mut StatorContext,
    }

    impl ContextGuard {
        fn new(iso: *mut StatorIsolate) -> Self {
            // SAFETY: caller passes a live isolate.
            let ctx = unsafe { stator_context_new(iso) };
            assert!(!ctx.is_null());
            Self { ctx }
        }
        fn as_ptr(&self) -> *mut StatorContext {
            self.ctx
        }
    }

    impl Drop for ContextGuard {
        fn drop(&mut self) {
            // SAFETY: `self.ctx` was created by `stator_context_new`.
            unsafe { stator_context_destroy(self.ctx) };
        }
    }

    #[test]
    fn test_persistent_new_null_args_returns_null() {
        let iso = IsolateGuard::new();
        let ctx = ContextGuard::new(iso.as_ptr());
        // SAFETY: passing null is documented as safe; should return null.
        let p1 = unsafe { stator_persistent_new(std::ptr::null_mut(), std::ptr::null_mut()) };
        assert!(p1.is_null());
        let p2 = unsafe { stator_persistent_new(ctx.as_ptr(), std::ptr::null_mut()) };
        assert!(p2.is_null());
        let val = unsafe { stator_value_new_number(iso.as_ptr(), 1.0) };
        let p3 = unsafe { stator_persistent_new(std::ptr::null_mut(), val) };
        assert!(p3.is_null());
        unsafe { stator_value_destroy(val) };
    }

    #[test]
    fn test_persistent_survives_handle_scope_close() {
        let iso = IsolateGuard::new();
        let ctx = ContextGuard::new(iso.as_ptr());
        // Open a handle scope, allocate an object, persist it, then close
        // the scope: the persistent must still let us read the object back.
        // SAFETY: `iso` is live.
        let scope = unsafe { stator_handle_scope_new(iso.as_ptr()) };
        assert!(!scope.is_null());
        let obj = unsafe { stator_object_new(iso.as_ptr()) };
        let key = c"answer";
        let val = unsafe { stator_value_new_number(iso.as_ptr(), 7.0) };
        unsafe { stator_object_set(obj, key.as_ptr(), val) };
        let obj_value = unsafe { stator_object_as_value(obj) };
        let persistent = unsafe { stator_persistent_new(ctx.as_ptr(), obj_value) };
        assert!(!persistent.is_null());
        assert!(!unsafe { stator_persistent_is_empty(persistent) });
        // Destroy the originating object handle now; the persistent should
        // still keep the underlying JsObject alive.
        unsafe { stator_object_destroy(obj) };
        unsafe { stator_handle_scope_close(scope) };

        // After the scope is closed, fetch a fresh value from the persistent
        // and confirm the property survived.
        let scope2 = unsafe { stator_handle_scope_new(iso.as_ptr()) };
        let materialized = unsafe { stator_persistent_get(persistent) };
        assert!(!materialized.is_null());
        let obj2 = unsafe { stator_value_as_object(materialized) };
        assert!(!obj2.is_null());
        let got = unsafe { stator_object_get(obj2, key.as_ptr()) };
        assert!(!got.is_null());
        let n = unsafe { stator_value_as_number(got) };
        assert!((n - 7.0).abs() < f64::EPSILON);
        unsafe { stator_object_destroy(obj2) };
        unsafe { stator_handle_scope_close(scope2) };
        unsafe { stator_persistent_dispose(persistent) };
    }

    #[test]
    fn test_persistent_survives_multiple_gc_cycles() {
        let iso = IsolateGuard::new();
        let ctx = ContextGuard::new(iso.as_ptr());
        let obj = unsafe { stator_object_new(iso.as_ptr()) };
        let key = c"k";
        let val = unsafe { stator_value_new_number(iso.as_ptr(), 99.0) };
        unsafe { stator_object_set(obj, key.as_ptr(), val) };
        let obj_value = unsafe { stator_object_as_value(obj) };
        let persistent = unsafe { stator_persistent_new(ctx.as_ptr(), obj_value) };
        unsafe { stator_value_destroy(val) };
        unsafe { stator_value_destroy(obj_value) };
        unsafe { stator_object_destroy(obj) };

        // Trigger several GC cycles; persistent must keep the object alive.
        for _ in 0..3 {
            unsafe { stator_isolate_gc(iso.as_ptr()) };
        }
        let materialized = unsafe { stator_persistent_get(persistent) };
        assert!(!materialized.is_null());
        let obj2 = unsafe { stator_value_as_object(materialized) };
        let got = unsafe { stator_object_get(obj2, key.as_ptr()) };
        assert!(!got.is_null());
        let n = unsafe { stator_value_as_number(got) };
        assert!((n - 99.0).abs() < f64::EPSILON);
        unsafe { stator_value_destroy(got) };
        unsafe { stator_object_destroy(obj2) };
        unsafe { stator_value_destroy(materialized) };
        unsafe { stator_persistent_dispose(persistent) };
    }

