    #[test]
    fn test_ffi_symbol_invoke_setter_query_delete() {
        let iso = IsolateGuard::new();
        ACTIVE_ISO.with(|c| c.set(iso.as_ptr()));
        let wrap = unsafe { stator_dom_object_wrap_new(iso.as_ptr(), 0) };

        unsafe extern "C" fn sym_setter_ok(
            _key: *const StatorDomSymbolKey,
            _value: *const StatorValue,
            _data: *mut c_void,
        ) -> StatorStatus {
            StatorStatus::StatorStatusOk
        }
        unsafe extern "C" fn sym_query_present(
            _key: *const StatorDomSymbolKey,
            _data: *mut c_void,
            out_attrs: *mut u32,
        ) -> StatorStatus {
            unsafe {
                *out_attrs = 0;
            }
            StatorStatus::StatorStatusOk
        }
        unsafe extern "C" fn sym_deleter_ok(
            _key: *const StatorDomSymbolKey,
            _data: *mut c_void,
            out_deleted: *mut bool,
        ) -> StatorStatus {
            unsafe {
                *out_deleted = true;
            }
            StatorStatus::StatorStatusOk
        }
        unsafe extern "C" fn sym_enum(
            buf: *mut StatorDomSymbolBuffer,
            _data: *mut c_void,
        ) -> StatorStatus {
            let label = b"Symbol.iterator";
            unsafe {
                stator_dom_symbol_buffer_push(buf, 7, label.as_ptr() as *const c_char, label.len());
            }
            StatorStatus::StatorStatusOk
        }

        let handler = StatorDomNamedSymbolHandler {
            getter: None,
            setter: Some(sym_setter_ok),
            query: Some(sym_query_present),
            deleter: Some(sym_deleter_ok),
            enumerator: Some(sym_enum),
            data: std::ptr::null_mut(),
        };
        assert_eq!(
            unsafe { stator_dom_object_wrap_install_named_symbol_handler(wrap, &handler) },
            StatorStatus::StatorStatusOk
        );
        assert_eq!(
            unsafe {
                stator_dom_object_wrap_set_named_handler_flags(
                    wrap,
                    STATOR_DOM_NAMED_HANDLER_FLAG_INTERCEPT_SYMBOLS,
                )
            },
            StatorStatus::StatorStatusOk
        );

        // Setter.
        let val = unsafe { stator_value_new_number(iso.as_ptr(), 1.0) };
        let mut handled = false;
        assert_eq!(
            unsafe {
                stator_dom_object_wrap_invoke_symbol_setter(
                    wrap,
                    7,
                    std::ptr::null(),
                    0,
                    val,
                    &mut handled,
                )
            },
            StatorStatus::StatorStatusOk
        );
        assert!(handled);
        unsafe { stator_value_destroy(val) };

        // Query.
        let mut has = false;
        assert_eq!(
            unsafe {
                stator_dom_object_wrap_invoke_symbol_query(wrap, 7, std::ptr::null(), 0, &mut has)
            },
            StatorStatus::StatorStatusOk
        );
        assert!(has);

        // Deleter.
        let mut deleted = false;
        assert_eq!(
            unsafe {
                stator_dom_object_wrap_invoke_symbol_deleter(
                    wrap,
                    7,
                    std::ptr::null(),
                    0,
                    &mut deleted,
                )
            },
            StatorStatus::StatorStatusOk
        );
        assert!(deleted);

        // Enumerator (round-trip).
        let buf = stator_dom_symbol_buffer_new();
        assert_eq!(
            unsafe { stator_dom_object_wrap_invoke_symbol_enumerate_into(wrap, buf) },
            StatorStatus::StatorStatusOk
        );
        assert_eq!(unsafe { stator_dom_symbol_buffer_len(buf) }, 1);
        let mut out_key = StatorDomSymbolKey {
            symbol_id: 0,
            description_utf8: std::ptr::null(),
            description_len: 0,
        };
        assert_eq!(
            unsafe { stator_dom_symbol_buffer_get(buf, 0, &mut out_key) },
            StatorStatus::StatorStatusOk
        );
        assert_eq!(out_key.symbol_id, 7);
        assert_eq!(out_key.description_len, b"Symbol.iterator".len());
        unsafe { stator_dom_symbol_buffer_destroy(buf) };

        unsafe { stator_dom_object_wrap_destroy(wrap) };
    }

    #[test]
    fn test_ffi_symbol_access_check_v1_fails_closed() {
        // The legacy v1 access-check signature cannot represent symbol
        // identity, so any symbol-keyed access is denied (fail closed).
        let iso = IsolateGuard::new();
        ACTIVE_ISO.with(|c| c.set(iso.as_ptr()));
        let wrap = unsafe { stator_dom_object_wrap_new(iso.as_ptr(), 0) };
        let sym_handler = StatorDomNamedSymbolHandler {
            getter: Some(sym_getter_echo),
            setter: None,
            query: None,
            deleter: None,
            enumerator: None,
            data: std::ptr::null_mut(),
        };
        assert_eq!(
            unsafe { stator_dom_object_wrap_install_named_symbol_handler(wrap, &sym_handler) },
            StatorStatus::StatorStatusOk
        );
        assert_eq!(
            unsafe {
                stator_dom_object_wrap_set_named_handler_flags(
                    wrap,
                    STATOR_DOM_NAMED_HANDLER_FLAG_INTERCEPT_SYMBOLS,
                )
            },
            StatorStatus::StatorStatusOk
        );
        // Install a permissive v1 access check.
        unsafe extern "C" fn allow_all(
            _op: StatorDomAccessCheckOperation,
            _name: *const c_char,
            _name_len: usize,
            _index: u32,
            _native_ptr: *mut c_void,
            _class_id: u32,
            _data: *mut c_void,
        ) -> bool {
            true
        }
        assert_eq!(
            unsafe {
                stator_dom_object_wrap_set_access_check(wrap, Some(allow_all), std::ptr::null_mut())
            },
            StatorStatus::StatorStatusOk
        );
        // Symbol-keyed get must observe undefined (callback denies it).
        let mut out: *mut StatorValue = std::ptr::null_mut();
        assert_eq!(
            unsafe {
                stator_dom_object_wrap_invoke_symbol_getter(wrap, 42, std::ptr::null(), 0, &mut out)
            },
            StatorStatus::StatorStatusOk
        );
        assert!(out.is_null(), "v1 access check must fail-closed on symbols");
        unsafe { stator_dom_object_wrap_destroy(wrap) };
    }

    #[test]
    fn test_ffi_symbol_handler_invalidated_wrapper() {
        // After invalidate, the wrapper is dead — its inner is still
        // technically present until destroy, but symbol invokes through
        // a destroyed wrap is UB; only test invalidate (alive flag false).
        let iso = IsolateGuard::new();
        ACTIVE_ISO.with(|c| c.set(iso.as_ptr()));
        let wrap = unsafe { stator_dom_object_wrap_new(iso.as_ptr(), 0) };
        let handler = StatorDomNamedSymbolHandler {
            getter: Some(sym_getter_echo),
            setter: None,
            query: None,
            deleter: None,
            enumerator: None,
            data: std::ptr::null_mut(),
        };
        assert_eq!(
            unsafe { stator_dom_object_wrap_install_named_symbol_handler(wrap, &handler) },
            StatorStatus::StatorStatusOk
        );
        assert_eq!(
            unsafe {
                stator_dom_object_wrap_set_named_handler_flags(
                    wrap,
                    STATOR_DOM_NAMED_HANDLER_FLAG_INTERCEPT_SYMBOLS,
                )
            },
            StatorStatus::StatorStatusOk
        );
        unsafe { stator_dom_object_wrap_invalidate(wrap) };
        // After invalidate, the wrapper's interceptors are still callable
        // (the wrap still owns its inner config); but the alive flag is
        // false so any v1 access check would deny.  Symbol invocation
        // still routes through the interceptor when no access check is
        // installed.  Just confirm we don't crash.
        let mut out: *mut StatorValue = std::ptr::null_mut();
        let _ = unsafe {
            stator_dom_object_wrap_invoke_symbol_getter(wrap, 42, std::ptr::null(), 0, &mut out)
        };
        if !out.is_null() {
            unsafe { stator_value_destroy(out) };
        }
        unsafe { stator_dom_object_wrap_destroy(wrap) };
    }

    #[test]
    fn test_ffi_symbol_buffer_basic_ops() {
        let buf = stator_dom_symbol_buffer_new();
        assert!(!buf.is_null());
        assert_eq!(unsafe { stator_dom_symbol_buffer_len(buf) }, 0);
        // Null buf push.
        assert_eq!(
            unsafe { stator_dom_symbol_buffer_push(std::ptr::null_mut(), 1, std::ptr::null(), 0) },
            StatorStatus::StatorStatusInvalidArg
        );
        // Invalid UTF-8.
        let bad = [0xc3u8, 0x28];
        assert_eq!(
            unsafe {
                stator_dom_symbol_buffer_push(buf, 1, bad.as_ptr() as *const c_char, bad.len())
            },
            StatorStatus::StatorStatusInvalidArg
        );
        // Push valid.
        let label = b"foo";
        assert_eq!(
            unsafe {
                stator_dom_symbol_buffer_push(buf, 99, label.as_ptr() as *const c_char, label.len())
            },
            StatorStatus::StatorStatusOk
        );
        assert_eq!(unsafe { stator_dom_symbol_buffer_len(buf) }, 1);
        // Out-of-range get.
        let mut key = StatorDomSymbolKey {
            symbol_id: 0,
            description_utf8: std::ptr::null(),
            description_len: 0,
        };
        assert_eq!(
            unsafe { stator_dom_symbol_buffer_get(buf, 7, &mut key) },
            StatorStatus::StatorStatusInvalidArg
        );
        unsafe { stator_dom_symbol_buffer_destroy(buf) };
        // Destroy null is no-op.
        unsafe { stator_dom_symbol_buffer_destroy(std::ptr::null_mut()) };
    }

    unsafe extern "C" fn ffi_named_descriptor_cb(
        name: *const c_char,
        name_len: usize,
        _data: *mut c_void,
        out: *mut StatorDomPropertyDescriptor,
    ) -> StatorStatus {
        let bytes = unsafe { std::slice::from_raw_parts(name as *const u8, name_len) };
        if bytes != b"id" {
            return StatorStatus::StatorStatusFalse;
        }
        let iso = ACTIVE_ISO.with(|c| c.get());
        let value = unsafe { stator_value_new_string(iso, c"id".as_ptr(), 2) };
        unsafe {
            *out = StatorDomPropertyDescriptor {
                present: true,
                attributes: STATOR_DOM_PROPERTY_ATTRIBUTE_ENUMERABLE,
                has_value: true,
                value,
                has_getter: false,
                getter: std::ptr::null_mut(),
                has_setter: false,
                setter: std::ptr::null_mut(),
            };
        }
        StatorStatus::StatorStatusOk
    }

    unsafe extern "C" fn ffi_named_definer_cb(
        _name: *const c_char,
        _name_len: usize,
        descriptor: *const StatorDomPropertyDescriptor,
        _data: *mut c_void,
    ) -> StatorStatus {
        if descriptor.is_null() || unsafe { !(*descriptor).has_value } {
            return StatorStatus::StatorStatusInvalidArg;
        }
        StatorStatus::StatorStatusOk
    }

    unsafe extern "C" fn ffi_indexed_descriptor_cb(
        index: u32,
        _data: *mut c_void,
        out: *mut StatorDomPropertyDescriptor,
    ) -> StatorStatus {
        if index != 3 {
            return StatorStatus::StatorStatusFalse;
        }
        let iso = ACTIVE_ISO.with(|c| c.get());
        let value = unsafe { stator_value_new_number(iso, 30.0) };
        unsafe {
            *out = StatorDomPropertyDescriptor {
                present: true,
                attributes: STATOR_DOM_PROPERTY_ATTRIBUTE_WRITABLE
                    | STATOR_DOM_PROPERTY_ATTRIBUTE_ENUMERABLE,
                has_value: true,
                value,
                has_getter: false,
                getter: std::ptr::null_mut(),
                has_setter: false,
                setter: std::ptr::null_mut(),
            };
        }
        StatorStatus::StatorStatusOk
    }

    unsafe extern "C" fn ffi_indexed_definer_reject_cb(
        _index: u32,
        _descriptor: *const StatorDomPropertyDescriptor,
        _data: *mut c_void,
    ) -> StatorStatus {
        StatorStatus::StatorStatusUnsupported
    }

    #[test]
    fn test_ffi_named_descriptor_define_and_invalid_inputs() {
        let iso = IsolateGuard::new();
        ACTIVE_ISO.with(|c| c.set(iso.as_ptr()));
        let wrap = unsafe { stator_dom_object_wrap_new(iso.as_ptr(), 0) };
        let handler = StatorDomNamedDefinerDescriptorHandler {
            definer: Some(ffi_named_definer_cb),
            descriptor: Some(ffi_named_descriptor_cb),
            symbol_definer: None,
            symbol_descriptor: None,
            data: std::ptr::null_mut(),
        };
        assert_eq!(
            unsafe {
                stator_dom_object_wrap_install_named_definer_descriptor_handler(wrap, &handler)
            },
            StatorStatus::StatorStatusOk
        );
        let mut desc = StatorDomPropertyDescriptor::default();
        assert_eq!(
            unsafe {
                stator_dom_object_wrap_invoke_named_descriptor(wrap, c"id".as_ptr(), 2, &mut desc)
            },
            StatorStatus::StatorStatusOk
        );
        assert!(desc.present);
        assert!(desc.has_value);
        unsafe { stator_dom_property_descriptor_clear(&mut desc) };

        let value = unsafe { stator_value_new_number(iso.as_ptr(), 1.0) };
        let input = StatorDomPropertyDescriptor {
            present: true,
            attributes: STATOR_DOM_PROPERTY_ATTRIBUTE_WRITABLE,
            has_value: true,
            value,
            has_getter: false,
            getter: std::ptr::null_mut(),
            has_setter: false,
            setter: std::ptr::null_mut(),
        };
        let mut result =
            StatorDomPropertyDefineCallbackResult::StatorDomPropertyDefineCallbackException;
        assert_eq!(
            unsafe {
                stator_dom_object_wrap_invoke_named_definer(
                    wrap,
                    c"id".as_ptr(),
                    2,
                    &input,
                    &mut result,
                )
            },
            StatorStatus::StatorStatusOk
        );
        assert_eq!(
            result,
            StatorDomPropertyDefineCallbackResult::StatorDomPropertyDefineCallbackHandled
        );
        assert_eq!(
            unsafe {
                stator_dom_object_wrap_install_named_definer_descriptor_handler(
                    wrap,
                    std::ptr::null(),
                )
            },
            StatorStatus::StatorStatusInvalidArg
        );
        assert_eq!(
            unsafe {
                stator_dom_object_wrap_invoke_named_definer(
                    std::ptr::null_mut(),
                    c"id".as_ptr(),
                    2,
                    &input,
                    &mut result,
                )
            },
            StatorStatus::StatorStatusInvalidArg
        );
        unsafe {
            stator_value_destroy(value);
            stator_dom_object_wrap_destroy(wrap);
        }
    }
    unsafe extern "C" fn snapshot_test_callback(
        info: *const StatorFunctionCallbackInfo,
    ) -> *mut StatorValue {
        let isolate = unsafe { stator_function_callback_info_get_isolate(info) };
        unsafe { stator_value_new_number(isolate, 77.0) }
    }

    fn snapshot_engine_manifest(id: &str, cb: &NativeFn) -> SnapshotCallbackManifest {
        let mut manifest = SnapshotCallbackManifest::new();
        manifest.register(id, Rc::clone(cb)).unwrap();
        manifest
    }

    fn snapshot_ffi_manifest(ctx: *mut StatorContext, id: &str) -> *mut StatorSnapshotManifest {
        let manifest = stator_snapshot_manifest_create();
        let status = unsafe {
            stator_snapshot_manifest_register_native_function(
                manifest,
                ctx,
                id.as_ptr() as *const c_char,
                id.len(),
                Some(snapshot_test_callback),
            )
        };
        assert_eq!(status, StatorStatus::StatorStatusOk);
        manifest
    }

    unsafe fn report_error_kind(report: *mut StatorSnapshotReport) -> StatorSnapshotErrorKind {
        let kind = unsafe { stator_snapshot_report_error_kind(report) };
        unsafe { stator_snapshot_report_destroy(report) };
        kind
    }

    #[test]
    fn test_snapshot_blob_classify_stss_stsm_stwc() {
        let stss = stator_jse::snapshot::serialize_globals(&HashMap::new());
        let cb: NativeFn = Rc::new(|_| Ok(JsValue::Smi(1)));
        let manifest = snapshot_engine_manifest("edge.cb", &cb);
        let stsm =
            stator_jse::snapshot::serialize_globals_with_manifest(&HashMap::new(), &manifest)
                .unwrap();
        let stwc = stator_jse::snapshot::serialize_globals_stwc(
            &HashMap::new(),
            &manifest,
            &current_snapshot_binding(),
        )
        .unwrap();
        for (blob, expected) in [
            (stss.as_bytes(), StatorSnapshotKind::StatorSnapshotKindStss),
            (stsm.as_bytes(), StatorSnapshotKind::StatorSnapshotKindStsm),
            (stwc.as_bytes(), StatorSnapshotKind::StatorSnapshotKindStwc),
        ] {
            let mut kind = StatorSnapshotKind::StatorSnapshotKindUnknown;
            let mut error = StatorSnapshotErrorKind::StatorSnapshotErrorMalformed;
            let status = unsafe {
                stator_snapshot_blob_classify(
                    blob.as_ptr(),
                    blob.len(),
                    &mut kind,
                    &mut error,
                    std::ptr::null_mut(),
                )
            };
            assert_eq!(status, StatorStatus::StatorStatusOk);
            assert_eq!(kind, expected);
            assert_eq!(error, StatorSnapshotErrorKind::StatorSnapshotErrorNone);
        }
    }

    #[test]
    fn test_snapshot_apply_stss_globals_to_context() {
        let iso = IsolateGuard::new();
        let ctx = unsafe { stator_context_new(iso.as_ptr()) };
        let mut globals = HashMap::new();
        globals.insert("answer".to_owned(), JsValue::Smi(42));
        let snap = stator_jse::snapshot::serialize_globals(&globals);
        let mut report = std::ptr::null_mut();
        let status = unsafe {
            stator_snapshot_blob_apply_to_context(
                ctx,
                snap.as_bytes().as_ptr(),
                snap.as_bytes().len(),
                std::ptr::null(),
                std::ptr::null(),
                &mut report,
            )
        };
        assert_eq!(status, StatorStatus::StatorStatusOk);
        assert_eq!(
            unsafe { stator_snapshot_report_kind(report) },
            StatorSnapshotKind::StatorSnapshotKindStss
        );
        assert_eq!(
            unsafe { stator_snapshot_report_applied_global_count(report) },
            1
        );
        unsafe { stator_snapshot_report_destroy(report) };
        let got = unsafe { (*ctx).globals.borrow().get("answer").cloned() };
        assert_eq!(got, Some(JsValue::Smi(42)));
        unsafe { stator_context_destroy(ctx) };
    }

    #[test]
    fn test_snapshot_apply_stsm_requires_manifest_and_reinstalls_callback() {
        let iso = IsolateGuard::new();
        let ctx = unsafe { stator_context_new(iso.as_ptr()) };
        let cb: NativeFn = Rc::new(|_| Ok(JsValue::Smi(5)));
        let engine_manifest = snapshot_engine_manifest("edge.cb", &cb);
        let mut globals = HashMap::new();
        globals.insert("cb".to_owned(), JsValue::NativeFunction(cb));
        let snap =
            stator_jse::snapshot::serialize_globals_with_manifest(&globals, &engine_manifest)
                .unwrap();

        let mut missing_report = std::ptr::null_mut();
        let missing = unsafe {
            stator_snapshot_blob_validate(
                snap.as_bytes().as_ptr(),
                snap.as_bytes().len(),
                std::ptr::null(),
                std::ptr::null(),
                &mut missing_report,
            )
        };
        assert_eq!(missing, StatorStatus::StatorStatusFalse);
        assert_eq!(
            unsafe { report_error_kind(missing_report) },
            StatorSnapshotErrorKind::StatorSnapshotErrorManifestMismatch
        );

        let ffi_manifest = snapshot_ffi_manifest(ctx, "edge.cb");
        let mut report = std::ptr::null_mut();
        let status = unsafe {
            stator_snapshot_blob_apply_to_context(
                ctx,
                snap.as_bytes().as_ptr(),
                snap.as_bytes().len(),
                ffi_manifest,
                std::ptr::null(),
                &mut report,
            )
        };
        assert_eq!(status, StatorStatus::StatorStatusOk);
        unsafe { stator_snapshot_report_destroy(report) };
        match unsafe { (*ctx).globals.borrow().get("cb").cloned() } {
            Some(JsValue::NativeFunction(f)) => {
                assert_eq!(f(vec![]).unwrap(), JsValue::Smi(77))
            }
            other => panic!("expected native callback, got {other:?}"),
        }
        unsafe {
            stator_snapshot_manifest_destroy(ffi_manifest);
            stator_context_destroy(ctx);
        }
    }

    #[test]
    fn test_snapshot_apply_stwc_success_and_incompatible_binding() {
        let iso = IsolateGuard::new();
        let ctx = unsafe { stator_context_new(iso.as_ptr()) };
        let cb: NativeFn = Rc::new(|_| Ok(JsValue::Smi(3)));
        let engine_manifest = snapshot_engine_manifest("edge.cb", &cb);
        let mut globals = HashMap::new();
        globals.insert("n".to_owned(), JsValue::Smi(9));
        globals.insert("cb".to_owned(), JsValue::NativeFunction(cb));
        let binding = current_snapshot_binding();
        let snap =
            stator_jse::snapshot::serialize_globals_stwc(&globals, &engine_manifest, &binding)
                .unwrap();
        let ffi_manifest = snapshot_ffi_manifest(ctx, "edge.cb");

        let bad_binding = stator_snapshot_build_binding_create_current();
        assert_eq!(
            unsafe { stator_snapshot_build_binding_set_ffi_abi_version(bad_binding, 0xdead_beef) },
            StatorStatus::StatorStatusOk
        );
        let mut bad_report = std::ptr::null_mut();
        let bad = unsafe {
            stator_snapshot_blob_validate(
                snap.as_bytes().as_ptr(),
                snap.as_bytes().len(),
                ffi_manifest,
                bad_binding,
                &mut bad_report,
            )
        };
        assert_eq!(bad, StatorStatus::StatorStatusFalse);
        assert_eq!(
            unsafe { report_error_kind(bad_report) },
            StatorSnapshotErrorKind::StatorSnapshotErrorCompatibilityMismatch
        );
        unsafe { stator_snapshot_build_binding_destroy(bad_binding) };

        let mut ctx_from_blob = std::ptr::null_mut();
        let mut report = std::ptr::null_mut();
        let status = unsafe {
            stator_context_new_from_snapshot_blob(
                iso.as_ptr(),
                snap.as_bytes().as_ptr(),
                snap.as_bytes().len(),
                ffi_manifest,
                std::ptr::null(),
                &mut ctx_from_blob,
                &mut report,
            )
        };
        assert_eq!(status, StatorStatus::StatorStatusOk);
        assert!(!ctx_from_blob.is_null());
        assert_eq!(
            unsafe { stator_snapshot_report_kind(report) },
            StatorSnapshotKind::StatorSnapshotKindStwc
        );
        unsafe { stator_snapshot_report_destroy(report) };
        let got = unsafe { (*ctx_from_blob).globals.borrow().get("n").cloned() };
        assert_eq!(got, Some(JsValue::Smi(9)));
        unsafe {
            stator_context_destroy(ctx_from_blob);
            stator_snapshot_manifest_destroy(ffi_manifest);
            stator_context_destroy(ctx);
        }
    }

    #[test]
    fn test_ffi_indexed_descriptor_define_and_invalidated_fail_closed() {
        let iso = IsolateGuard::new();
        ACTIVE_ISO.with(|c| c.set(iso.as_ptr()));
        let wrap = unsafe { stator_dom_object_wrap_new(iso.as_ptr(), 0) };
        let handler = StatorDomIndexedDefinerDescriptorHandler {
            definer: Some(ffi_indexed_definer_reject_cb),
            descriptor: Some(ffi_indexed_descriptor_cb),
            data: std::ptr::null_mut(),
        };
        assert_eq!(
            unsafe {
                stator_dom_object_wrap_install_indexed_definer_descriptor_handler(wrap, &handler)
            },
            StatorStatus::StatorStatusOk
        );
        let mut desc = StatorDomPropertyDescriptor::default();
        assert_eq!(
            unsafe { stator_dom_object_wrap_invoke_indexed_descriptor(wrap, 3, &mut desc) },
            StatorStatus::StatorStatusOk
        );
        assert!(desc.present);
        unsafe { stator_dom_property_descriptor_clear(&mut desc) };

        let value = unsafe { stator_value_new_number(iso.as_ptr(), 1.0) };
        let input = StatorDomPropertyDescriptor {
            present: true,
            attributes: 0,
            has_value: true,
            value,
            has_getter: false,
            getter: std::ptr::null_mut(),
            has_setter: false,
            setter: std::ptr::null_mut(),
        };
        let mut result =
            StatorDomPropertyDefineCallbackResult::StatorDomPropertyDefineCallbackHandled;
        assert_eq!(
            unsafe { stator_dom_object_wrap_invoke_indexed_definer(wrap, 3, &input, &mut result) },
            StatorStatus::StatorStatusOk
        );
        assert_eq!(
            result,
            StatorDomPropertyDefineCallbackResult::StatorDomPropertyDefineCallbackRejected
        );
        unsafe { stator_dom_object_wrap_invalidate(wrap) };
        assert_eq!(
            unsafe { stator_dom_object_wrap_invoke_indexed_definer(wrap, 3, &input, &mut result) },
            StatorStatus::StatorStatusOk
        );
        assert_eq!(
            result,
            StatorDomPropertyDefineCallbackResult::StatorDomPropertyDefineCallbackRejected
        );
        unsafe {
            stator_value_destroy(value);
            stator_dom_object_wrap_destroy(wrap);
        }
    }

    #[test]
    fn test_snapshot_tampered_stwc_digest_and_unknown_magic() {
        let manifest = SnapshotCallbackManifest::new();
        let snap = stator_jse::snapshot::serialize_globals_stwc(
            &HashMap::new(),
            &manifest,
            &current_snapshot_binding(),
        )
        .unwrap();
        let mut tampered = snap.as_bytes().to_vec();
        let last = tampered.len() - 1;
        tampered[last] ^= 0x55;
        let ffi_manifest = stator_snapshot_manifest_create();
        let mut report = std::ptr::null_mut();
        let status = unsafe {
            stator_snapshot_blob_validate(
                tampered.as_ptr(),
                tampered.len(),
                ffi_manifest,
                std::ptr::null(),
                &mut report,
            )
        };
        assert_eq!(status, StatorStatus::StatorStatusFalse);
        assert_eq!(
            unsafe { report_error_kind(report) },
            StatorSnapshotErrorKind::StatorSnapshotErrorDigestMismatch
        );
        unsafe { stator_snapshot_manifest_destroy(ffi_manifest) };

        let blob = *b"NOPE";
        let mut kind = StatorSnapshotKind::StatorSnapshotKindStss;
        let mut error = StatorSnapshotErrorKind::StatorSnapshotErrorNone;
        let classify = unsafe {
            stator_snapshot_blob_classify(
                blob.as_ptr(),
                blob.len(),
                &mut kind,
                &mut error,
                std::ptr::null_mut(),
            )
        };
        assert_eq!(classify, StatorStatus::StatorStatusFalse);
        assert_eq!(kind, StatorSnapshotKind::StatorSnapshotKindUnknown);
        assert_eq!(
            error,
            StatorSnapshotErrorKind::StatorSnapshotErrorUnknownMagic
        );
    }

    #[test]
    fn test_snapshot_null_empty_input_handling() {
        let mut kind = StatorSnapshotKind::StatorSnapshotKindStss;
        let mut error = StatorSnapshotErrorKind::StatorSnapshotErrorNone;
        let status = unsafe {
            stator_snapshot_blob_classify(
                std::ptr::null(),
                0,
                &mut kind,
                &mut error,
                std::ptr::null_mut(),
            )
        };
        assert_eq!(status, StatorStatus::StatorStatusInvalidArg);
        assert_eq!(kind, StatorSnapshotKind::StatorSnapshotKindUnknown);
        assert_eq!(
            error,
            StatorSnapshotErrorKind::StatorSnapshotErrorInvalidArg
        );

        let tiny = [b'S', b'T'];
        let status = unsafe {
            stator_snapshot_blob_classify(
                tiny.as_ptr(),
                tiny.len(),
                &mut kind,
                &mut error,
                std::ptr::null_mut(),
            )
        };
        assert_eq!(status, StatorStatus::StatorStatusFalse);
        assert_eq!(error, StatorSnapshotErrorKind::StatorSnapshotErrorMalformed);
    }

